const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');

sendgrid.setApiKey('SG.azure_demo_key_123');

const accountSid = 'AC1234567890abcdef';
const authToken = 'your_twilio_auth_token'; // Replace with your Twilio Auth Token
const client = new twilio(accountSid, authToken);

module.exports = async function (context, req) {
    const email = req.body.email;
    const smsTo = req.body.smsTo;
    const smsBody = req.body.smsBody;

    try {
        // Send email
        await sendgrid.send({
            to: email,
            from: 'noreply@example.com',
            subject: 'Hello from Azure Function',
            text: 'This is a test email sent from Azure Function.',
        });

        // Send SMS
        await client.messages.create({
            body: smsBody,
            from: 'your_twilio_phone_number', // Replace with your Twilio phone number
            to: smsTo,
        });

        context.res = {
            status: 200,
            body: "Email and SMS sent successfully.",
        };
    } catch (error) {
        context.log(error);
        context.res = {
            status: 500,
            body: "Error sending email or SMS.",
        };
    }
};